using System;
using System.Linq;

class Program
{
    static void Main(string[] args)
    {
        int[] numbers = { 1, 2, 3, 4, 5, 6 };

        // Sorğu sintaksisi ilə cüt ədədləri seçmək
        var evenNumbers = from n in numbers
                         where n % 2 == 0
                         select n;

        Console.WriteLine("Cüt ədədlər: " + string.Join(", ", evenNumbers));
    }
}
// Output:
// Cüt ədədlər: 2, 4, 6

using System;
using System.Linq;

class Program
{
    static void Main(string[] args)
    {
        int[] numbers = { 1, 2, 3, 4, 5, 6 };

        // Metod sintaksisi ilə cüt ədədləri seçmək
        var evenNumbers = numbers.Where(n => n % 2 == 0);
        Console.WriteLine("Cüt ədədlər: " + string.Join(", ", evenNumbers));

        // Kvadratları hesablamaq
        var squares = numbers.Select(n => n * n);
        Console.WriteLine("Kvadratlar: " + string.Join(", ", squares));
    }
}
// Output:
// Cüt ədədlər: 2, 4, 6
// Kvadratlar: 1, 4, 9, 16, 25, 36

using System;
using System.Linq;

class Program
{
    static void Main(string[] args)
    {
        string[] fruits = { "alma", "armud", "banan", "çiyələk" };

        // Uzunluğu 5-dən böyük sözləri sıralamaq
        var longFruits = fruits.Where(f => f.Length > 4)
                               .OrderBy(f => f);
        Console.WriteLine("Uzun və sıralanmış sözlər: " + string.Join(", ", longFruits));

        // İlk elementi seçmək
        var firstFruit = fruits.First();
        Console.WriteLine("İlk meyvə: " + firstFruit);

        // Elementlərin sayını hesablamaq
        var count = fruits.Count();
        Console.WriteLine("Meyvələrin sayı: " + count);
    }
}
// Output:
// Uzun və sıralanmış sözlər: armud, çiyələk
// İlk meyvə: alma
// Meyvələrin sayı: 4

using System;
using System.Linq;

class Person
{
    public string Name { get; set; }
    public int Age { get; set; }
}

class Program
{
    static void Main(string[] args)
    {
        Person[] people = {
            new Person { Name = "Ali", Age = 25 },
            new Person { Name = "Aygün", Age = 30 },
            new Person { Name = "Cavid", Age = 20 }
        };

        // 25 yaşdan böyük insanları seçmək və sıralamaq
        var adults = from p in people
                     where p.Age > 25
                     orderby p.Name
                     select p.Name;

        Console.WriteLine("Yetkinlər: " + string.Join(", ", adults));
    }
}
// Output:
// Yetkinlər: Aygün

