using System;
using System.Linq;

class Student
{
    public string Name { get; set; }
    public int Grade { get; set; }
}

class Program
{
    static void Main(string[] args)
    {
        Student[] students = {
            new Student { Name = "Ali", Grade = 85 },
            new Student { Name = "Aygün", Grade = 90 },
            new Student { Name = "Cavid", Grade = 70 }
        };

        // 80-dən yuxarı qiymətləri olan tələbələri sıralamaq
        var highGrades = students.Where(s => s.Grade > 80)
                                .OrderBy(s => s.Grade)
                                .Select(s => s.Name);
        Console.WriteLine("Yüksək qiymətlər: " + string.Join(", ", highGrades));

        // Orta qiyməti hesablamaq
        var averageGrade = students.Average(s => s.Grade);
        Console.WriteLine($"Orta qiymət: {averageGrade}");
    }
}
// Output:
// Yüksək qiymətlər: Ali, Aygün
// Orta qiymət: 81.66666666666667

