using System;
using System.Linq;

class Program
{
    static void Main(string[] args)
    {
        string[] fruits = { "apple", "pear", "banana", "strawberry" };

        // Filter words longer than 4 characters and sort
        var longFruits = fruits.Where(f => f.Length > 4)
                               .OrderBy(f => f);
        Console.WriteLine("Long and sorted words: " + string.Join(", ", longFruits));

        // Select the first element
        var firstFruit = fruits.First();
        Console.WriteLine("First fruit: " + firstFruit);

        // Count the elements
        var count = fruits.Count();
        Console.WriteLine("Number of fruits: " + count);
    }
}
// Output:
// Long and sorted words: banana, strawberry
// First fruit: apple
// Number of fruits: 4

